func TestGenerator_Generate_TemplatePathOverride(t *testing.T) {
	outDir := filepath.Join(t.TempDir(), "models")
	templateDir := filepath.Join(t.TempDir(), "templates")

	files := map[string]string{
		"header.go.tmpl": `package {{ .PackageName }}

const HeaderOverrideMarker = "header override"
`,
		"spanner_db.go.tmpl": `package {{ .PackageName }}

type SpannerDB interface{}

var SpannerLog = func(...any) {}

const SpannerDBOverrideMarker = "spanner override"
`,
		"type.go.tmpl": `package {{ .PackageName }}

type {{ .Type.Name }} struct{}

func Find{{ .Type.Name }}ByPrimaryKey(db SpannerDB) string {
	_ = db
	return "{{ .Type.Table }}"
}
`,
	}

	for name, content := range files {
		writeTextFile(t, filepath.Join(templateDir, name), content)
	}

	if err := NewGenerator(Options{
		OutDir:       outDir,
		PackageName:  "models",
		TemplatePath: templateDir,
	}).Generate(newSimpleSchema("Users")); err != nil {
		t.Fatalf("Generate() error = %v", err)
	}

	tests := map[string]struct {
		path string
		want string
	}{
		"header": {
			path: filepath.Join(outDir, "spanner_header.spanner.go"),
			want: `HeaderOverrideMarker = "header override"`,
		},
		"helper": {
			path: filepath.Join(outDir, "spanner_db.spanner.go"),
			want: `SpannerDBOverrideMarker = "spanner override"`,
		},
		"type": {
			path: filepath.Join(outDir, "users.spanner.go"),
			want: `return "Users"`,
		},
	}

	for name, tt := range tests {
		t.Run(name, func(t *testing.T) {
			content := readTextFile(t, tt.path)
			if !strings.Contains(content, tt.want) {
				t.Fatalf("%s missing %q", tt.path, tt.want)
			}
		})
	}
}

func TestDetectGoModuleConfig(t *testing.T) {
	tests := map[string]struct {
		setup          func(t *testing.T) string
		wantModulePath string
		wantLang       string
	}{
		"success: nearest go.mod is used": {
			setup: func(t *testing.T) string {
				root := t.TempDir()
				writeTextFile(t, filepath.Join(root, "go.mod"), "module example.com/acme/project\n\ngo 1.26\n")
				outDir := filepath.Join(root, "internal", "models")
				if err := os.MkdirAll(outDir, 0o755); err != nil {
					t.Fatalf("creating out dir: %v", err)
				}
				return outDir
			},
			wantModulePath: "example.com/acme/project",
			wantLang:       "go1.26",
		},
		"success: no go.mod returns empty config": {
			setup: func(t *testing.T) string {
				return t.TempDir()
			},
			wantModulePath: "",
			wantLang:       "",
		},
	}

	for name, tt := range tests {
		t.Run(name, func(t *testing.T) {
			outDir := tt.setup(t)
			gotModulePath, gotLang := detectGoModuleConfig(outDir)
			if gotModulePath != tt.wantModulePath || gotLang != tt.wantLang {
				t.Fatalf("detectGoModuleConfig(%q) = (%q, %q), want (%q, %q)", outDir, gotModulePath, gotLang, tt.wantModulePath, tt.wantLang)
			}
		})
	}
}

